# MCP Compatible Schemas - Addition to schemas.py\n\n# Quiz Schemas for MCP\nclass QuizCreate(BaseModel):\n    title: str = Field(..., min_length=1, max_length=255)\n    description: Optional[str] = None\n    lesson_id: UUID  \n    questions_data: List[Dict[str, Any]] = Field(default_factory=list)\n    difficulty_level: str = Field(default=\"beginner\", pattern=\"^(beginner|intermediate|advanced)$\")\n    time_limit_minutes: Optional[int] = Field(None, ge=1)\n    passing_score: float = Field(default=70.0, ge=0.0, le=100.0)\n\n\nclass QuizUpdate(BaseModel):\n    title: Optional[str] = Field(None, min_length=1, max_length=255)\n    description: Optional[str] = None\n    questions_data: Optional[List[Dict[str, Any]]] = None\n    difficulty_level: Optional[str] = Field(None, pattern=\"^(beginner|intermediate|advanced)$\")\n    time_limit_minutes: Optional[int] = Field(None, ge=1)\n    passing_score: Optional[float] = Field(None, ge=0.0, le=100.0)\n    is_active: Optional[bool] = None\n
